```class Solution {
public:
    int minInsertions(string s) {
        int res = 0, need = 0;
        for (char c : s) {
            if (c == '(') need++;
            else {
                if (need == 0) res++;
                else need--;
                res += need % 2;
                need /= 2;
            }
        }
        res += need * 2;
        return res;
    }
};
```
